import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { FaSearch, FaUserCircle, FaSignOutAlt, FaCloudUploadAlt } from 'react-icons/fa';

const Navbar = () => {
  const { user, logout } = useAuth();
  const [search, setSearch] = useState("");
  const navigate = useNavigate();

  const handleSearch = (e) => {
    e.preventDefault();
    navigate(`/?q=${search}`);
  };

  const handleLogout = () => {
    logout();
    navigate('/login'); // Chuyển hướng về trang đăng nhập sau khi thoát
  };

  return (
    <nav className="bg-gray-900 text-white p-3 flex justify-between items-center sticky top-0 z-40 shadow-lg h-14">
      <Link to="/" className="text-xl font-bold text-orange-500 flex items-center gap-2 ml-2">
        ☁️ Mini SoundCloud
      </Link>

      <form onSubmit={handleSearch} className="flex-1 max-w-md mx-4 relative hidden md:block">
        <input 
            type="text" 
            placeholder="Search for artists, bands, tracks..." 
            className="w-full py-1.5 px-3 rounded bg-gray-800 border border-gray-700 focus:outline-none focus:border-gray-500 text-sm text-gray-200"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
        />
        <button type="submit" className="absolute right-2 top-2 text-gray-400 hover:text-white"><FaSearch /></button>
      </form>

      <div className="flex items-center gap-4 text-sm font-medium mr-2">
        <Link to="/" className="hover:text-white text-gray-300 hidden sm:block">Home</Link>
        {user ? (
            <>
                <Link to="/upload" className="hover:text-white text-gray-300 flex items-center gap-1">
                    <FaCloudUploadAlt /> <span className="hidden sm:inline">Upload</span>
                </Link>
                
                {/* Đường kẻ dọc ngăn cách */}
                <div className="h-6 w-px bg-gray-700 mx-1"></div>

                <div className="flex items-center gap-3">
                    {/* Sửa đoạn này: Dùng Link bao quanh User Info */}
                    <Link to="/profile" className="flex items-center gap-2 text-gray-300 select-none hover:text-white transition group">
                        <div className="w-7 h-7 rounded-full overflow-hidden bg-gray-600 border border-gray-500 group-hover:border-white">
                             {/* Avatar nhỏ trên navbar */}
                             <img src={`https://ui-avatars.com/api/?name=${user.username}&background=random`} alt="avt" className="w-full h-full object-cover" />
                        </div>
                        <span className="hidden md:inline max-w-[100px] truncate font-medium">{user.username}</span>
                    </Link>
                    
                    {/* Nút Sign Out */}
                    <button 
                        onClick={handleLogout} 
                        className="flex items-center gap-1 bg-gray-800 hover:bg-red-600 text-gray-300 hover:text-white px-3 py-1.5 rounded transition text-xs font-bold border border-gray-700 hover:border-red-500"
                        title="Sign Out"
                    >
                        <FaSignOutAlt /> <span className="hidden sm:inline">Sign Out</span>
                    </button>
                </div>
            </>
        ) : (
            <>
                <Link to="/login" className="border border-gray-500 px-3 py-1 rounded text-gray-300 hover:border-white hover:text-white transition text-xs font-bold">Sign in</Link>
                <Link to="/register" className="bg-orange-500 px-3 py-1 rounded text-white hover:bg-orange-600 transition text-xs font-bold">Create account</Link>
            </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
